#[test]
fn test_rust_chunking_process() {
    // Intel: chunk multi-function Rust source into pieces
    let source = r#"fn alpha() {}

fn beta() {}

fn gamma() {}

fn delta() {}
"#;
    let config_json: serde_json::Value = serde_json::from_str(r#"{"chunk_max_size":30,"language":"rust"}"#).unwrap();
    let config = serde_json::from_value(config_json).unwrap();
    let result = process(source, &config).expect("should succeed");
    let chunks = &result.chunks;
    assert_eq!(
        result.language.to_string().as_str().trim(),
        r#"rust"#,
        "equals assertion failed"
    );
    assert!(result.metrics.total_lines >= 7, "expected >= 7");
    assert!(chunks.len() >= 2 as usize, "expected >= 2 chunks");
}

